import{_ as a,o as d,c as o,ao as i}from"./chunks/framework.Cg2N26K4.js";const h=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"changelog.md","filePath":"changelog.md","lastUpdated":null}'),t={name:"changelog.md"};function n(r,e,l,c,s,p){return d(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="Changelog" tabindex="-1">Changelog <a class="header-anchor" href="#Changelog" aria-label="Permalink to &quot;Changelog {#Changelog}&quot;">​</a></h1><h2 id="Unreleased" tabindex="-1">Unreleased <a class="header-anchor" href="#Unreleased" aria-label="Permalink to &quot;Unreleased {#Unreleased}&quot;">​</a></h2><ul><li><p>Added pedigree normalization and sparse <code>Ainv</code> construction utilities.</p></li><li><p>Added low-level animal-model specification validation.</p></li><li><p>Added dense Gaussian ML/REML log-likelihood evaluation at supplied variance components.</p></li><li><p>Added sparse REML log-likelihood evaluation at supplied variance components using the Henderson MME determinant identity.</p></li><li><p>Expanded planned backend marker/control vocabulary to include threaded CPU, AMDGPU, Metal, and oneAPI markers alongside CPU, CUDA, and auto metadata.</p></li><li><p>Added <code>backend_info()</code> typed status diagnostics for planned backend rows with execution marked unavailable.</p></li><li><p>Added planned genomic/QTL model-term vocabulary reservations: <code>genomic()</code>, <code>single_step()</code>, <code>markers()</code>, <code>marker_scan()</code>, and <code>qtl_scan()</code>.</p></li><li><p>Added planned standard quantitative-genetic model-term vocabulary reservations: <code>permanent()</code>, <code>common_env()</code>, <code>maternal_genetic()</code>, <code>maternal_env()</code>, <code>paternal_genetic()</code>, <code>paternal_env()</code>, <code>cytoplasmic()</code>, <code>imprinting()</code>, <code>dominance()</code>, <code>epistasis()</code>, <code>relmat()</code>, and <code>HSquared.precision()</code> in direct Julia code.</p></li><li><p>Added a Documenter model-spec grammar page mirroring the R twin&#39;s status separation for parsed, reserved, and planned syntax.</p></li><li><p>Added <code>formula_status()</code> grammar diagnostics and a Documenter status table mirroring the R twin&#39;s parsed/reserved/planned grammar rows.</p></li><li><p>Added <code>validation_status()</code> diagnostics for covered, external, partial, and planned validation rows.</p></li><li><p>Added <code>max_dense_cells</code> guards for the temporary dense validation path.</p></li><li><p>Added experimental dense variance-component optimization for validated low-level animal-model specs.</p></li><li><p>Added experimental low-level variance-component, fixed-effect, EBV/BLUP, fitted-value, and heritability extractors for the dense spec path.</p></li><li><p>Switched <code>breeding_values(fit)</code> to the Henderson MME solve at the fit&#39;s variance components.</p></li><li><p>Added experimental dense prediction-error-variance and reliability extractors for the dense spec path.</p></li><li><p>Extended validation-scale prediction-error-variance and reliability extractors to supplied-variance <code>HendersonMMEResult</code> objects.</p></li><li><p>Extended supplied-variance <code>variance_components()</code> and <code>heritability()</code> extractors to <code>HendersonMMEResult</code> objects.</p></li><li><p>Added experimental direct payload <code>fit_animal_model(y, X, Z, Ainv; ...)</code> target for bridge-shaped inputs.</p></li><li><p>Added <code>henderson_mme()</code> for sparse Henderson mixed-model-equation solving at supplied variance components.</p></li><li><p>Added a shared R/Julia Henderson mixed-model-equation validation fixture for the supplied-variance output path.</p></li><li><p>Added <code>result_payload()</code> with field names aligned to the R <code>hsquared_fit</code> extractor contract.</p></li><li><p>Added <code>HSData</code>, <code>HSDataIDMap</code>, and <code>id_map()</code> as an in-memory mirror of the R <code>hs_data()</code> input-container contract.</p></li><li><p>Added <code>HSData</code> marker-map metadata validation and genotype-marker alignment checks.</p></li><li><p>Added <code>data_status(::HSData)</code> diagnostics mirroring the R twin&#39;s <code>data_status()</code> surface for component presence, ID-overlap counts, pedigree status, and marker-alignment status. Diagnostic only; no bridge payload, raw-pedigree Ainv construction, genotype parsing, relationship construction, marker scan, genomic fitting, or QTL/eQTL claim.</p></li><li><p>Added <code>sparse_csc_matrix()</code> for R <code>Matrix::dgCMatrix</code> slot marshalling.</p></li><li><p>Recorded the R twin&#39;s PEV/reliability bridge extractor contract while keeping Julia <code>result_payload()</code> fields unchanged.</p></li><li><p>Recorded the R twin&#39;s tiny/local bridge enrichment of PEV/reliability from exported Julia extractors, still without widening base <code>result_payload()</code>.</p></li><li><p>Recorded the R twin&#39;s opt-in supplied-variance Henderson MME bridge target, with explicit no-log-likelihood/no-variance-estimation boundary.</p></li><li><p>Recorded the R twin&#39;s sparse <code>Z</code> bridge marshalling handoff.</p></li><li><p>Recorded the R twin&#39;s optional <code>nadiv::Mrode9</code> pedigree-Ainv comparator evidence.</p></li><li><p>Recorded the R twin&#39;s <code>model_spec()</code> preview surface for the v0.1 formula-to-bridge payload.</p></li><li><p>Recorded the R twin&#39;s <code>hs_data()</code> parser integration for the v0.1 formula-to-bridge payload without changing the Julia payload shape.</p></li><li><p>Recorded the R twin&#39;s <code>animal(1 | id)</code> shorthand for <code>data = hs_data(..., pedigree = ped)</code> as R-side formula ergonomics only; the explicit <code>animal(1 | id, pedigree = ped)</code> contract and Julia payload shape are unchanged.</p></li><li><p>Added DocumenterVitepress documentation scaffold.</p></li><li><p>Added audience and comparator programme notes.</p></li><li><p>Added genomics/QTL/eQTL/GLLVM/GPU/HPC strategic roadmap.</p></li><li><p>Added a backend and algorithm roadmap page for CPU, threads, CUDA, AMDGPU, Metal, oneAPI, AI-REML, Takahashi selected inversion, Woodbury paths, APY, and claim gates.</p></li><li><p>Kept high-level fitting entry points as honest placeholders.</p></li></ul>',3)])])}const g=a(t,[["render",n]]);export{h as __pageData,g as default};
